import*as Schema from"../schema.js";import Validation from"./validation.js";const id="https://json-schema.org/keyword/dynamicRef",experimental=!0,compile=Schema.value,interpret=(e,t,a,l,o)=>{if(e in l)return Validation.interpret(l[e],t,a,l,o);throw Error(`No dynamic anchor found for "${e}"`)},collectEvaluatedProperties=Validation.collectEvaluatedProperties,collectEvaluatedItems=Validation.collectEvaluatedItems;export default{id:id,experimental:experimental,compile:compile,interpret:interpret,collectEvaluatedProperties:collectEvaluatedProperties,collectEvaluatedItems:collectEvaluatedItems};